var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......왔군.","JPN":"……来たな。","ENG":"They're here.","TWN":"……來了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"지, 지휘관님! 외곽 방어선이 뚫렸습니다!","JPN":"し、指揮官！　外郭の防衛線が破られました！","ENG":"C-Commander! Our outer defense line is breaking!","TWN":"指，指揮官大人！週邊防禦網被突破了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"호들갑 떨지 마! 이 정도의 전투가 벌어지는데 사령부에서 모를 리가 없다!","JPN":"騒ぐな！　司令部でこの規模の戦闘を把握していないはずがない！","ENG":"Stay calm. There's no way that the high command isn't aware of a battle of this scale.","TWN":"不要大驚小怪的！都發生了這樣的戰鬥，司令部不可能不知道的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"조금만 있으면 사령부 병력과 간부들이 지원하러 올 거야!","JPN":"もうじき司令部の兵力や幹部らが支援に駆け付ける！","ENG":"Just hold on, and the officers will bring reinforcements from the high command!","TWN":"過一會，司令部的兵力和幹部就會來支援的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"근거리에 있는 다른 부대들도 곧 합류하러 올 거다! 조금만 버텨라!!","JPN":"近くにいる他の部隊も、間もなく合流するはずだ！　もう少しだけ耐えろ！！","ENG":"Other forces in the nearby areas will come join us as well! Just hold the line for a little longer!","TWN":"在附近的部隊也會支援我們的！再堅持一會！"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"하, 하지만......","JPN":"で、ですが……","ENG":"B-but...","TWN":"但、但是……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"안녕, 비숍 재생체 나으리.","JPN":"こんにちは、ビショップ再生体さん。","ENG":"Hi there, Regenerated Bishop.","TWN":"你好，大主教再生體大人。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이런 자리에서 만나게 돼서 유감이야.","JPN":"こんなところで会うなんて残念ね。","ENG":"I'm sorry that we have to meet like this.","TWN":"在這裡見到妳真是遺憾呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"당신에게 공적인 용무는 없지만, 이것도 뭐 개인적인 감정이라서 말이야.","JPN":"あなたに用はないけど、個人的に片づけなければならないことがあって。","ENG":"I just want you to know, I'm not doing this for a great cause. It's strictly personal, every single bit of it.","TWN":"找妳雖然沒有什麼公事要辦，但倒是有些私事要處理。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"당신도 딱히 리플레이서에게 살아 있는 컴퓨터 취급이나 받는 게 즐겁진 않겠지?","JPN":"あなたも、リプレイサーに物みたいな扱いをされて嬉しくはないでしょ？","ENG":"You don't exactly find it amusing to be treated as a walking computer by your colleagues, do you?","TWN":"妳應該也不怎麼高興被克隆集團當作一台活體機器來對待吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러니까 인심 쓰는 셈 치고 여기서 죽......","JPN":"だから、ここは一つ目をつぶって、死んで……","ENG":"So why don't you do us a favor and die here—","TWN":"所以就當作是對妳的仁慈，在這裡死了也……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아니, 생각해 보니 어차피 진짜 리플레이서 비숍은 죽었잖아?","JPN":"いや、本物のリプレイサー・ビショップはすでに死んでるんだった。","ENG":"No, come to think of it, the real Replacer Bishop already died.","TWN":"不，仔細想想，反正真正的克隆大主教也死了對吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러니까...... 작동정지 시켜 줄게.","JPN":"だったら……作動停止してあげる。","ENG":"So... I'm going to turn you off for good,","TWN":"所以……就讓妳停止運轉吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"영원히, 다시는 켤 수 없도록.","JPN":"永遠に起動できないように。","ENG":"and make sure you don't go walking around ever again.","TWN":"讓妳永遠無法再啟動。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대, 대장...... 너무 악당 같아......","JPN":"た、隊長……悪党みたい……","ENG":"C-Cap... You sounded like a very mean movie villain...","TWN":"隊，隊長……太像壞人了……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"너, 너도 그렇게 느꼈냐? 실은 나도......","JPN":"お、お前もそう思ったか？　実は俺も……","ENG":"I-I know, right? I was feeling the same...","TWN":"妳、妳也這麼覺得嗎？其實我也……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};